function initTab(e){let t=GetElemCache();const s=e.className;e.addEventListener("click",(()=>{for(const e in t.sections){const c=t.sections[e];e==s?c.classList.remove("is-hidden"):c.classList.add("is-hidden")}for(const e of t.tabs)e.parentElement.classList.remove("is-active");e.parentElement.classList.add("is-active")}))}export const GetElemCache=(()=>{let e={tabs:document.querySelectorAll("#tabs > .tabs > ul > li > a"),sections:{reels:document.querySelector("#reels"),projects:document.querySelector("#projects"),music:document.querySelector("#music"),compositions:document.querySelector("#compositions")}};return()=>e})();document.addEventListener("DOMContentLoaded",(()=>{let e=GetElemCache();for(const t of e.tabs)initTab(t);e.tabs[0].click()}));